            with open(meta_file, 'r') as f:
                meta = json.load(f)
            
            # Check expiration
            ttl = ttl or meta.get('ttl', self.default_ttl)
            if self._is_expired(meta['timestamp'], ttl):
                # Remove expired cache files
                cache_file.unlink(missing_ok=True)
                meta_file.unlink(missing_ok=True)
                return None
            
            # Read data
